/**
 * File-backed `RecordLog` — spec §11.1, plan Task 13.5.
 *
 * One JSONL file per `run_id` under `baseDir/<run_id>.jsonl`. Each
 * line is a single JSON-encoded `PersistedRecord`. Append-only;
 * line ordering is preserved within a single `run_id`.
 *
 * ## Sync writes for the test surface (v1)
 *
 * The interface inherits the sync `append(record): void` signature
 * from `RecordLog` (Phase 3 Task 12). The file-backed impl uses
 * `fs.appendFileSync` so the call site stays synchronous — the
 * loop's `host.persistRecord(record)` doesn't need `await`.
 *
 * This is acceptable for the Phase 4 test surface (small files,
 * few records). Production's persistent log (Phase 5, beyond
 * Task 13.5) can be backed by an async tail/append pattern, an
 * embedded store like SQLite, or an external log service if scale
 * demands it. The `RecordLog` interface is preserved across all
 * impls so the swap is transparent to the loop.
 *
 * ## Crash semantics
 *
 * Append-only means a crashed run's records are intact on disk
 * and recoverable by `resumeRun`. `latestCheckpoint(runId)` walks
 * the file in reverse to find the last `checkpoint_snapshot`
 * without replaying events — per §11.1 ("the snapshot *is* the
 * state").
 *
 * The base directory is created on construction (idempotent
 * `mkdirSync({ recursive: true })`).
 */

import { appendFileSync, existsSync, mkdirSync, readdirSync, readFileSync } from "node:fs";
import { join } from "node:path";

import type { Checkpoint } from "../core/types.js";
import type { PersistedRecord, RecordLog } from "../persistence/log.js";

export interface FileRecordLogOptions {
  /** Directory holding the run_id-keyed JSONL files. Created on construction. */
  readonly baseDir: string;
}

export class FileRecordLog implements RecordLog {
  private readonly baseDir: string;

  constructor(opts: FileRecordLogOptions) {
    this.baseDir = opts.baseDir;
    mkdirSync(this.baseDir, { recursive: true });
  }

  append(record: PersistedRecord): void {
    const runId = runIdOf(record);
    const line = `${JSON.stringify(record)}\n`;
    appendFileSync(this.filePath(runId), line, "utf8");
  }

  latestCheckpoint(runId: string): Checkpoint | null {
    const records = this.records(runId);
    for (let i = records.length - 1; i >= 0; i--) {
      const r = records[i];
      if (r && r.type === "checkpoint_snapshot") {
        return r.checkpoint;
      }
    }
    return null;
  }

  records(runId: string): readonly PersistedRecord[] {
    const filePath = this.filePath(runId);
    if (!existsSync(filePath)) return Object.freeze([]);
    const content = readFileSync(filePath, "utf8");
    const lines = content.split("\n").filter((l) => l.length > 0);
    const records: PersistedRecord[] = [];
    for (const line of lines) {
      // Each line is a single JSON-encoded record. Schema changes
      // between SDK / core versions surface here as parse errors
      // — fail loud, no silent fallbacks (AGENTS.md).
      records.push(JSON.parse(line) as PersistedRecord);
    }
    return Object.freeze(records);
  }

  listRunIds(): readonly string[] {
    if (!existsSync(this.baseDir)) return Object.freeze([]);
    const files = readdirSync(this.baseDir);
    const ids = files.filter((f) => f.endsWith(".jsonl")).map((f) => f.slice(0, -".jsonl".length));
    return Object.freeze(ids);
  }

  close(): void {
    // Sync impl: no file descriptor held open. No-op.
  }

  private filePath(runId: string): string {
    return join(this.baseDir, `${runId}.jsonl`);
  }
}

/** Extract the run_id from a record. CheckpointSnapshot carries it on the wrapped Checkpoint. */
function runIdOf(record: PersistedRecord): string {
  return record.type === "checkpoint_snapshot" ? record.checkpoint.run_id : record.run_id;
}

snapshot to a per-run JSONL log on disk — the durable system of record. It
also exposes a typed, **in-process emitter** that fans out the same records
to *separately installed* extensions in the same `pi` process. The emitter
is a read-side extension point: `pi-conductor` ships zero upload code, zero
network code, zero server config — just a public function a consumer can
call to register a listener and receive every record the host persists.

The intended consumer is a *separately installed* pi extension living in
`~/.pi/agent/extensions/` (per the pi extensions spec, "Extensions" — auto-
discovery). It is not part of `pi-conductor` and is not published alongside
it. The consumer owns auth, retry, batching, backpressure, and the durable
replay of anything the listener missed. The spec's only contract is
`subscribeToRecords` and the durable log.

### The public API

A single module-level function exported from `pi-conductor`'s public barrel:

```ts
import {
  subscribeToRecords,
  type PersistedRecord,
} from "pi-conductor";

const unsubscribe = subscribeToRecords((record: PersistedRecord) => {
  // Do whatever you want with the record. The host fires listeners
  // fire-and-forget — async listeners are NOT awaited. Errors thrown
  // from a listener (sync or async) are isolated and do not affect
  // the engine or other listeners.
});
```

`PersistedRecord` is the existing union from `src/persistence/log.ts`:
`transition_accepted`, `transition_rejected`, `session_started` /
`session_ended` / `session_failed`, `model_fallback`, and
`checkpoint_snapshot`. No new record types are added; the emitter is a
transparent fan-out of what the host already persists.

The contract — FIFO subscription order, fire-and-forget async delivery,
sync-throw and async-rejection isolation, re-entrant subscribe /
unsubscribe (effects take place on the next record), idempotent unsubscribe,
and the durable backstop pattern — is in
[`docs/record-emitter-spec.md`](docs/record-emitter-spec.md) (the authority).

### A consumer extension

A minimal separately-installed extension at
`~/.pi/agent/extensions/conductor-uploader.ts`:

```ts
import {
  subscribeToRecords,
  type PersistedRecord,
} from "pi-conductor";
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";

export default function (pi: ExtensionAPI) {
  const serverUrl = process.env.CONDUCTOR_UPLOAD_URL;
  if (serverUrl === undefined) {
    pi.events.once("session_start", (_e, ctx) => {
      ctx.ui.notify(
        "conductor-uploader: CONDUCTOR_UPLOAD_URL not set; extension disabled",
        "warning",
      );
    });
    return;
  }

  // Live delivery: every record the host persists goes to the server.
  subscribeToRecords(async (record: PersistedRecord) => {
    const res = await fetch(serverUrl, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify(record),
    });
    if (!res.ok) throw new Error(`upload failed: ${res.status}`);
  });

  // Backstop: on session_start, walk the log dir to ship records the
  // listener might have missed (consumer's watermark strategy lives in
  // this extension's own state file; the durable log is read via the
  // FileRecordLog implementation in pi-conductor's persistence module).
  pi.events.on("session_start", async () => {
    /* replayMissedRecords(serverUrl) — consumer-private */
  });
}
```

